class AllternitMiniMax {
  apiKey;
  groupId;
  baseURL;
  constructor(options) {
    this.apiKey = options.apiKey;
    this.groupId = options.groupId || process.env.MINIMAX_GROUP_ID;
    this.baseURL = options.baseURL || "https://api.minimax.chat/v1";
  }
  async chat(options) {
    const url = this.groupId ? `${this.baseURL}/text/chatcompletion_v2?GroupId=${this.groupId}` : `${this.baseURL}/text/chatcompletion_v2`;
    const response = await fetch(url, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${this.apiKey}`
      },
      body: JSON.stringify({
        model: options.model,
        messages: options.messages,
        temperature: options.temperature,
        max_tokens: options.maxTokens,
        top_p: options.topP,
        stream: false,
        functions: options.functions,
        function_call: options.functionCall
      })
    });
    if (!response.ok) {
      const error3 = await response.json().catch(() => ({ base_resp: { status_msg: "Unknown error" } }));
      throw new HarnessError(error3.base_resp?.status_msg || `MiniMax API error: ${response.status}`, HarnessErrorCode.PROVIDER_ERROR, { statusCode: response.status });
    }
    const data = await response.json();
    if (data.base_resp && data.base_resp.status_code !== 0) {
      throw new HarnessError(data.base_resp.status_msg, HarnessErrorCode.PROVIDER_ERROR, { statusCode: data.base_resp.status_code });
    }
    return data;
  }
  async* chatStream(options) {
    const url = this.groupId ? `${this.baseURL}/text/chatcompletion_v2?GroupId=${this.groupId}` : `${this.baseURL}/text/chatcompletion_v2`;
    const response = await fetch(url, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${this.apiKey}`,
        Accept: "text/event-stream"
      },
      body: JSON.stringify({
        model: options.model,
        messages: options.messages,
        temperature: options.temperature,
        max_tokens: options.maxTokens,
        top_p: options.topP,
        stream: true,
        functions: options.functions,
        function_call: options.functionCall
      })
    });
    if (!response.ok) {
      const error3 = await response.json().catch(() => ({ base_resp: { status_msg: "Unknown error" } }));
      throw new HarnessError(error3.base_resp?.status_msg || `MiniMax API error: ${response.status}`, HarnessErrorCode.PROVIDER_ERROR, { statusCode: response.status });
    }
    const reader = response.body.getReader();
    const decoder = new TextDecoder;
    let buffer = "";
    try {
      while (true) {
        const { done, value } = await reader.read();
        if (done)
          break;
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split(`
`);
        buffer = lines.pop() || "";
        for (const line of lines) {
          if (line.trim() === "" || line.trim() === "data: [DONE]")
            continue;
          if (line.startsWith("data: ")) {
            try {
              const chunk = JSON.parse(line.slice(6));
              yield chunk;
            } catch {}
          }
        }
      }
    } finally {
      reader.releaseLock();
    }
  }
  async listModels() {
    return [
      { id: MINIMAX_MODELS.ABA5_5, name: "ABAB 5.5" },
      { id: MINIMAX_MODELS.ABA5_5S, name: "ABAB 5.5s" },
      { id: MINIMAX_MODELS.ABA6, name: "ABAB 6" },
      { id: MINIMAX_MODELS.ABA6_5, name: "ABAB 6.5" },
      { id: MINIMAX_MODELS.ABA6_5S, name: "ABAB 6.5s" }
    ];
  }
}
